set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
# shellcheck source=../lib/common.sh
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="心理咨询 / 心理治疗(临床实践者视角 — 接案与评估 / 个案概念化 / 主流流派技术(CBT 与第三浪潮 / 精神动力 / 人本存在 / 家庭系统 / 创伤治疗) / 伦理边界与危机干预 / 督导与个人成长 / 执业形态与经营 — 涵盖中国大陆行业现状 + 欧美持照体系,两套体系差异极大)"
DIM_COUNT=8

usage() {
  cat <<EOF
agentic.sh — Agentic Protocol CLI for ${INDUSTRY}

拿到 ${INDUSTRY} 行业的新问题时，按 ${DIM_COUNT} 个研究维度做功课再答。
不直接给答案，而是引导你用资深从业者的研究维度收集信息。

USAGE:
  ./agentic.sh                # interactive walkthrough
  ./agentic.sh --dry-run      # walk through but skip file write
  ./agentic.sh --json         # emit JSON to stdout
  ./agentic.sh --explain      # show backing mental models + sources
  ./agentic.sh --help         # this message
EOF
}

explain() {
  cat <<'EOT'
这个 Agentic Protocol 把这一行人面对新问题的研究维度结构化。

研究维度 (8 个):
  9.1 locale 与执业体系判定(推导自心智模型 1.7)
  9.2 流派语境与「障碍 × 证据 × 来访者」匹配(推导自心智模型 1.1 + 1.4)
  9.3 个案概念化就绪度审计(推导自心智模型 1.3)
  9.4 危机与风险硬边界核查(推导自心智模型 1.5)
  9.5 结构性伦理 / 法律硬约束扫描(推导自心智模型 1.5 + 1.6)
  9.6 督导与治疗师职业健康评估(推导自心智模型 1.8)
  9.7 大众流行说法 vs 临床共识甄别(推导自心智模型 1.2 + 1.4)
  9.8 工具栈与时效 / 监管变动追踪(推导自心智模型 1.6 + 1.7 + 时效信号)

背后的心智模型:
  • 治疗关系 / 共同要素 > 单一技术: 这一行的资深人默认「治疗关系的质量、共情、期望、来访者因素」这些**跨流派共有的共同要素**对疗效的解释力,可能不亚于任一流派的特定技术 —— 所以「学对了流派」从来不够,「谁来做、和来访者建立了什么
  • 症状是有功能 / 是适应,不是单纯的「病」: 这一行的人看一个症状,默认先问「它在为这个人 / 这个系统**做什么**」—— 症状常是某个困境下能找到的最优解、是适应而非缺陷,去病理化地理解它,比急着「消除」它更接近治疗。
  • 个案概念化是跨流派的核心临床能力 —— 诊断 ≠ 概念化: 诊断(DSM / ICD)回答「这组症状叫什么、和精神科 / 保险怎么对话」;**个案概念化**回答「这个人为什么现在这样、什么在维持、从哪个点切入阻力最小」—— 后者是把症状 / 史 / 关系 / 

来源: synthesis.md Section 9 + Section 1.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a DIM_TITLES=(
  "locale 与执业体系判定(推导自心智模型 1.7)"
  "流派语境与「障碍 × 证据 × 来访者」匹配(推导自心智模型 1.1 + 1.4)"
  "个案概念化就绪度审计(推导自心智模型 1.3)"
  "危机与风险硬边界核查(推导自心智模型 1.5)"
  "结构性伦理 / 法律硬约束扫描(推导自心智模型 1.5 + 1.6)"
  "督导与治疗师职业健康评估(推导自心智模型 1.8)"
  "大众流行说法 vs 临床共识甄别(推导自心智模型 1.2 + 1.4)"
  "工具栈与时效 / 监管变动追踪(推导自心智模型 1.6 + 1.7 + 时效信号)"
)
declare -a DIM_QUESTIONS=(
  "这个问题 / 这个从业者面向中国大陆还是欧美持照体系 —— locale 决定整套执业资质路径、伦理守则、转介逻辑、监管框架;若 locale = 中国大陆,自动触发「2017 后无中心化法定准入 + 认证市场噪音」语境。"
  "这个问题涉及或这个从业者在哪个流派(CBT 与第三浪潮 / 精神动力 / 人本-存在-体验 / 家庭系统 / 整合-共同要素);针对的障碍在循证清单上的证据图景如何;**并把文化适配作为一个核对项**(西方框架的默认假设是否需为该来访者群体调整)。"
  "这个个案 / 这个问题有没有一个成文的、动态可证伪的个案概念化(回答「什么在维持、资源在哪、从哪切入阻力最小」)—— 还是只有一个 DSM / ICD 诊断标签;概念化是不是在被持续回测和修订。"
  "这个对话 / 这个个案是否出现危机信号(自杀念头 / 计划 / 既往尝试、自伤升级、透露受虐或施虐、急性精神病性症状);若有,识别是否直接具体、是否用了结构化工具、下一步安全去向是否已落实且与风险等级匹配、是否履行了法定报告 / 警告义务、是否调动了上级督导。"
  "这个情境涉及哪些**结构性**(非急性危机)伦理 / 法律硬约束 —— 知情同意(含保密法定例外)、保密及例外、双重 / 多重关系、胜任力范围、记录管理;并分清「这是硬规定」还是「需要权衡的真两难」。"
  "这个从业者有没有持续的、有质量的督导(不只「有一个上级督导师」,还有同辈督导 / 同行咨询);有没有把个人体验当回事;对替代性创伤 / 共情耗竭 / 收入不稳定的真实风险有没有清醒认知与管理。"
  "这个对话里出现的概念 / 引用的作者,是「大众心理流行说法」还是「临床共识」—— 流行词(原生家庭 / PUA / NPD / 内耗 / 课题分离 / 疗愈)对应的临床精确构念是什么;引用的高影响力作者(如武志红)与临床学界共识的距离。"
  "这个从业者的工具选型(临床仪器:量表 / 诊断系统 / 风险评估;执业基础设施:EHR / 远程视频 / 督导继教)是否符合「信效度 + 临床定位 + 版权可得性 + 使用资质」+「合规是硬约束」;以及该 locale 近 3-6 个月有没有标准 / 监管 / 政策的外部变动。"
)
declare -a DIM_SOURCES=(
  "对话 / intake 里「在哪执业 / 受训」「想考什么证」的表述;对照 §7.3 海外 vs 国内分叉、§4 的 W7(欧美持照路径)vs W8(中国大陆路径);海外查 APA / BACP / UKCP 注册框架,国内查中国心理学会临床与咨询心理学注册系统(注意官网访问不稳定)。"
  "对话里「用什么流派 / 什么技术」的表述;查 APA Division 12 清单(障碍 × 流派二维表)、Cochrane 系统综述、NICE 指南;对照 §7.1 五大流派代表 + §7.2 核心分歧;文化适配查 canon C27 + §8.8。"
  "对话里对来访者的描述 —— 是停在「他是抑郁症」级别,还是有「什么在维持」的因果假设;对照 §4 W3 入门 SOP 的 5 步标准 + canon C1 / C26 + §1.3。"
  "对话内容里的危机信号;对照 §4 W4 硬边界 SOP + §2 规则 4 + C-SSRS(Track 02 必备工具)+ 本地危机资源(美国 988 等,注意号码会变需更新)。"
  "对话里的伦理张力信号(礼物 / 自我暴露 / 治疗外关系交集 / 记录调取请求 / AI scribe 使用 / 平台数据);查所属伦理守则(按 locale:美国 APA / 英国 BACP / 中国心理学会注册系统);对照 §4 W6 + §6.2「伦理 / 胜任力级」反模式 + §8.9。"
  "对话里关于督导习惯、个人体验、职业状态的表述;对照 §4 W9(督导贯穿职业生涯)+ W7 / W8 的资深 add + §1.8 + §8.10;canon C18 治疗师效应 + C6 反移情。"
  "对话里的术语用法;对照 §8.6 + §7.5 + Track 06「临床共识术语 vs 大众心理流行说法」对照表 + 「行业拒绝的厂商话术」。"
  "对话里用什么工具的表述;对照 §3 工具栈三层 + 选型决策树 + 避坑清单;时效查 §8.12 —— 中国执业准入政策(T06-S015/S016)、DSM-5-TR / ICD-11、美国跨州协约、988 危机生命线、AI scribe 进 EHR、FTC 对 BetterHelp 的执法令、Div12 / NICE / Cochrane 滚动更新。"
)
declare -a DIM_OUTPUT_FORMATS=(
  "「locale = {中国大陆 / 欧美持照体系(美国 LMFT/LCSW/LPC/博士 / 英国 BACP/UKCP)};适用执业路径 = {对应 W7 / W8};若中国大陆:当前无法定统一准入,专业身份锚点 = 注册系统 + 连续培训谱系,须警惕『速成考证』噪音。」"
  "「该问题属流派 {①/②/③/④/⑤ 或混合};针对障碍 {X} 的循证图景 = {强证据疗法 / 证据形态不同的疗法};建议按『障碍 × 证据 × 来访者偏好与文化』匹配 {1-2 个方向},理由 {1 句};**不站队 —— 「哪个流派最好」是错误问题**;文化适配核对 = {需 / 不需调整,具体哪点}。」"
  "「个案概念化就绪度 = {到位:能一句话说清维持机制 / 不到位:只有诊断标签,给出补全方向};是否成文可修订 = {是 / 否};是否纳入了治疗关系与过程素材 = {是 / 否};提醒:技术选择应跟在概念化之后。」"
  "「危机信号 = {无 / 有:具体哪类};若有:识别是否到位 {是 / 否}、是否用结构化工具 {是 / 否}、下一步安全去向 {已落实且匹配风险等级 / 缺失}、法定义务 {已履行 / N/A / 缺失}、上级督导 {已调动 / 待调动};**任何真实危机:立即导向当地危机热线 / 急诊**。」"
  "「涉及的伦理 / 法律约束 = {列 1-3 条};每条是 {硬规定:直接照走 / 需权衡的两难:走结构化推理};建议动作 = {查哪条守则 + 咨询督导 / 同行 + 记录推理过程};提醒:把硬边界当可商量很危险,把真两难当有标准答案则僵化。」"
  "「督导状态 = {健康:持续 + 有质量 + 含同辈 / 风险:具体哪项缺失};个人体验 = {重视 / 忽视};职业健康风险认知 = {清醒并在管理 / 缺位};提醒:治疗师本人是工具,需要被维护 —— 持照 / 成熟后停止一切督导是职业不可持续信号。」"
  "「该概念 / 作者 = {临床共识 / 大众流行说法:具体被简化成什么样};对应的临床精确构念 = {如『原生家庭』→ 依恋类型 / 内在工作模型 / 客体关系 / 家庭系统,且强调可改变性};提醒:大众流行词不是错的,但用法和精度与临床概念差距很大;隔空下诊断违反伦理。」"
  "「工具选型 = {合理 / 有问题:具体哪项 —— 如『把筛查量表当诊断工具』『用消费版视频做远程治疗』『无资质用 MMPI』};该 locale 近 3-6 月变动 = {1-3 条具体标准 / 监管变化 + 日期};对该从业者的影响 = {评估 / 记录 / 远程 / 执业地理哪一环};建议动作 = {1 句}。」"
)
declare -a DIM_FINDINGS=()

if [[ $JSON -eq 0 ]]; then
  ms_section "${INDUSTRY} · Agentic Protocol"
  ms_info "拿到的问题是什么? (输入完后，敲一个空行结束)"
  echo
fi

PROBLEM="$(ms_read_multiline)"
ms_buffer_append "# ${INDUSTRY} — Agentic Protocol Report"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## 问题"
ms_buffer_append ""
ms_buffer_append "$PROBLEM"
ms_buffer_append ""

for i in "${!DIM_TITLES[@]}"; do
  if [[ $JSON -eq 0 ]]; then
    ms_section "${DIM_TITLES[$i]}"
    echo "看什么:    ${DIM_QUESTIONS[$i]}"
    echo "在哪看:    ${DIM_SOURCES[$i]}"
    echo "输出格式:  ${DIM_OUTPUT_FORMATS[$i]}"
    echo
    ms_prompt "你的发现 / 推断 (空行结束):"
    echo
  fi
  finding="$(ms_read_multiline)"
  DIM_FINDINGS+=("$finding")

  ms_buffer_append "## ${DIM_TITLES[$i]}"
  ms_buffer_append ""
  ms_buffer_append "**看什么**: ${DIM_QUESTIONS[$i]}"
  ms_buffer_append ""
  ms_buffer_append "**在哪看**: ${DIM_SOURCES[$i]}"
  ms_buffer_append ""
  ms_buffer_append "**发现**:"
  ms_buffer_append ""
  ms_buffer_append "$finding"
  ms_buffer_append ""
done

if [[ $JSON -eq 1 ]]; then
  args=("problem" "$PROBLEM")
  for i in "${!DIM_TITLES[@]}"; do
    args+=("dim_${i}_title" "${DIM_TITLES[$i]}")
    args+=("dim_${i}_finding" "${DIM_FINDINGS[$i]}")
  done
  ms_emit_json "${args[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "agentic-protocol"
fi
